def interval_gaps(intervals, start, end):
    if not intervals or start >= end:
        return [[start, end]] if start < end else []

    # Sort intervals by start time
    sorted_intervals = sorted(intervals)

    # Merge overlapping intervals
    merged = []
    if sorted_intervals:
        current_start, current_end = sorted_intervals[0]
        for next_start, next_end in sorted_intervals[1:]:
            if next_start < current_end:
                current_end = max(current_end, next_end)
            else:
                merged.append([current_start, current_end])
                current_start, current_end = next_start, next_end
        merged.append([current_start, current_end])

    # Find gaps
    gaps = []
    current_pos = start

    for interval_start, interval_end in merged:
        if interval_start > current_pos:
            gaps.append([current_pos, interval_start])
        current_pos = max(current_pos, interval_end)

    if current_pos < end:
        gaps.append([current_pos, end])

    return gaps
```

