from collections import deque

def topological_sort(graph):
    in_degree = {node: 0 for node in graph}

    # Calculate in-degrees based on the dependents mapping
    # If A must come before B (A -> B), then B has an incoming edge from A.
    # The input format is {node: [dependents]}, so for each dependent, increment its in-degree.
    for node in graph:
        for dependent in graph[node]:
            if dependent not in in_degree:
                in_degree[dependent] = 0
            in_degree[dependent] += 1

    # Initialize queue with nodes having no dependencies (in-degree 0)
    queue = deque([node for node, degree in in_degree.items() if degree == 0])
    result = []

    while queue:
        current = queue.popleft()
        result.append(current)

        # Reduce in-degree of dependents
        for dependent in graph.get(current, []):
            in_degree[dependent] -= 1
            if in_degree[dependent] == 0:
                queue.append(dependent)

    # If result count doesn't match total nodes, there's a cycle
    if len(result) != len(in_degree):
        raise ValueError("Graph contains a cycle")

    return result
```

