def interval_gaps(intervals, start, end):
    if not intervals:
        return [[start, end]]

    # Sort intervals by start time
    sorted_intervals = sorted(intervals)

    merged_occupied = []
    current_start, current_end = sorted_intervals[0][0], sorted_intervals[0][1]

    for i in range(1, len(sorted_intervals)):
        next_start, next_end = sorted_intervals[i]
        if next_start < current_end:
            current_end = max(current_end, next_end)
        else:
            merged_occupied.append([current_start, current_end])
            current_start, current_end = next_start, next_end
    merged_occupied.append([current_start, current_end])

    # Calculate gaps between start and the first occupied interval, 
    # between occupied intervals, and after the last occupied interval to end
    result = []

    if merged_occupied[0][0] > start:
        result.append([start, merged_occupied[0][0]])

    for i in range(len(merged_occupied) - 1):
        gap_start = merged_occupied[i][1]
        gap_end = merged_occupied[i+1][0]
        if gap_start < gap_end:
            result.append([gap_start, gap_end])

    if merged_occupied[-1][1] < end:
        result.append([merged_occupied[-1][1], end])

    return result
```

